import logo from './logo.svg';
import './App.css';
import { Route, Router } from 'react-router-dom';
import home from './pages/home'
import abount from './pages/abount'

import produsk from './pages/produsk'


function App() {
  return (
    <div className="App">

      <Router>
        <Route path='/' element={<home/>}></Route>
        <Route path='./abount.js' element={<abount/>}></Route>
        <Route path='./produsk.js' element={<produsk/>}></Route>

      </Router>

    </div>
  );
}

export default App;
